/**
 * Sets the squared size of this rectangle
 *
 * @param sizeXY The size
 * @return this rectangle for chaining
 */
public RectangleMutant setSize(float sizeXY) {
    this.width = sizeXY;
    this.height = sizeXY;
    return this;
}
